INSERT INTO [dbo].[Products] ([Id], [Name], [LongDescription], [Price], [Stock], [ImageFilename], [ProductCategoryId], [ManufacturerId], [ArticleNo], [VisibleInShop], [ShortDescription]) VALUES (20, N'Dell Pro 14 Intel Core', N'DELL Pro 14 är en kompakt företagslaptop som balanserar snabb respons med praktisk hanterbarhet. Den ger dig en Intel Core processor och en 14-tums 16:10 FHD+-skärm för tydligare dokument och videomöten, hårdvarubaserad säkerhet och förberedelser för fjärrhantering som minskar IT-belastningen, samt snabb trådbunden och trådlös anslutning som håller teamen produktiva på resande fot.', 11799, 10, N'dell-pro-14-intel-core.webp', 2, 3, N'5020082706', 1, N'Dell Pro 14 är en kompakt företagslaptop med en 14-tums 16:10 FHD+ skärm och Intel Core processor.')
INSERT INTO [dbo].[Products] ([Id], [Name], [LongDescription], [Price], [Stock], [ImageFilename], [ProductCategoryId], [ManufacturerId], [ArticleNo], [VisibleInShop], [ShortDescription]) VALUES (24, N'Dell Pro Slim Plus - Intel Core Ultra 7265 ', N'Dell Pro Slim Plus - Intel Core Ultra 7265.

Stationär dator med 14-kärnig Intel Core i5 processor upp till 5 GHz ger snabb prestanda för kontorsappar.

1 x 16 GB DDR5 4800 MHz minne gör multitasking smidigt även vid hög belastning.

512 GB SSD startar Windows 11 Pro och lagrar program lokalt.

Inbyggd TPM och Windows 11 Pro hjälper till att skydda företagsdata.

Slank svart chassi sparar skrivbordsutrymme, inkluderar tangentbord och mus.', 21594, 10, N'Dell Pro Slim Plus Intel Core Ultra 7265-01.webp', 3, 3, N'QBS1250', 1, N'Stationär dator med 14-kärnig Intel Core i5 processor upp till 5 GHz. 16 GB DDR5 minne. 512GB SSD disk. Windows 11 pro.')
INSERT INTO [dbo].[Products] ([Id], [Name], [LongDescription], [Price], [Stock], [ImageFilename], [ProductCategoryId], [ManufacturerId], [ArticleNo], [VisibleInShop], [ShortDescription]) VALUES (27, N'Dell Pro Slim Intel Core Ultra 5 16GB 512GB', N'Stationär dator med kompakt, slimmat chassi får enkelt plats bredvid eller under en bildskärm. 
Intel Core Ultra 5, 14 effektiva kärnor och upp till 5 GHz turbofrekvens. 
16 GB DDR5 5600 MHz och 512 GB SSD ger snabb multitasking. 
Inbyggd AI-acceleration upp till 13 TOPS snabbar upp intelligenta appar. 
Windows 11 Pro med TPM och testversion av Microsoft 365 förenklar säker installation.
', 8811, 10, N'dell-pro-slim-intel-core-ultra-5-16gb-512gb.webp', 3, 3, N'5020082706', 1, N'Stationär dator med kompakt, slimmat chassi. Processor, Intel Core Ultra 5. Minne 16 GB DDR5 och 512 GB SSD. Windows 11 Pro')
